+fn collect_input_lines(input: PipelineData, args: &Arguments) -> Result<Vec<String>, ShellError> {
+    let skip = args.num_rows_to_skip.unwrap_or_default();
+
+    match input {
+        PipelineData::ByteStream(stream, ..) => {
+            if !stream.type_().is_string_coercible() {
+                return Err(ShellError::TypeMismatch {
+                    err_message: "expected string, but got binary".into(),
+                    span: stream.span(),
+                });
+            }
+
+            let Some(lines) = stream.lines() else {
+                return Ok(Vec::new());
+            };
+
+            lines.skip(skip).collect()
+        }
+        input => Ok(input
+            .collect_string("", &args.config)?
+            .lines()
+            .skip(skip)
+            .map(|line| line.to_string())
+            .collect()),
+    }
